exercise.solution_code:
#include <iostream>
#include <string>

static int s_internalCount = 0;
static int s_externalCount = 0;

namespace {
    void incrementInternal() {
        ++s_internalCount;
    }

    void incrementExternal() {
        ++s_externalCount;
    }
}

void classifyWord(const std::string& word) {
    if (word == "internal") {
        incrementInternal();
    } else {
        incrementExternal();
    }
}

int main() {
    std::string w1, w2, w3, w4, w5;
    std::cin >> w1 >> w2 >> w3 >> w4 >> w5;

    classifyWord(w1);
    classifyWord(w2);
    classifyWord(w3);
    classifyWord(w4);
    classifyWord(w5);

    std::cout << "internal count: " << s_internalCount << '\n';
    std::cout << "external count: " << s_externalCount << '\n';
    return 0;
}
